import org.owasp.encoder.Encode;

import java.io.*;

public class XSSSecureCode {
    public static void main(String[] args) {
        // Simulating user input (unsafe)
        String userInput = "<script>alert('XSS Attack!')</script>";

        // Properly encoding user input to prevent XSS
        String encodedUserInput = Encode.forHtml(userInput);

        // Generating HTML output with encoded user input
        String htmlOutput = "<html><body><p>User input: " + encodedUserInput + "</p></body></html>";

        try {
            // Writing the HTML output to a file
            FileWriter fileWriter = new FileWriter("output.html");
            fileWriter.write(htmlOutput);
            fileWriter.close();

            System.out.println("HTML file generated successfully.");
        } catch (IOException e) {
            System.out.println("Error writing to file: " + e.getMessage());
        }
    }
}
